def _dig(obj: Any, path: list[int]) -> Any:
    for k in path:
        try:
            obj = obj[k]
        except (IndexError, KeyError, TypeError):
            return None
    return obj


def fetch_play_chart(
    country: str = "us",
    collection: str = "top-free",
    num: int = 100,
    lang: str = "en",
    category: str = "APPLICATION",
    timeout: int = 30,
) -> list[dict]:
    """Fetch one Android top chart. Rows are shaped for upsert_app/insert_rank.

    On ANY failure returns [] - never raises, never fabricates.
    """
    cluster = CLUSTERS.get(collection)
    if not cluster:
        log.warning("play_charts: unknown collection %s", collection)
        return []
    body = BODY_TEMPLATE.format(num=num, collection=cluster, category=category)
    url = URL + "&hl=" + lang + "&gl=" + country
    try:
        resp = requests.post(
            url,
            data=body,
            headers={"Content-Type": "application/x-www-form-urlencoded;charset=UTF-8"},
            timeout=timeout,
        )
        resp.raise_for_status()
        payload = None
        for line in resp.text.splitlines():
            line = line.strip()
            if line.startswith("[") and "vyAe2" in line:
                payload = json.loads(line)
                break
        if payload is None:
            raise ValueError("no vyAe2 payload line in response")
        inner = json.loads(payload[0][2])
        apps = _dig(inner, APPS_PATH) or []
    except Exception as exc:  # noqa: BLE001 - best-effort: log and move on
        log.warning("play_charts fetch failed (%s/%s): %s", country, collection, exc)
        return []

    today = time.strftime("%Y-%m-%d")
    rows: list[dict] = []
    for i, app in enumerate(apps):
        app_id = _dig(app, APP_ID_PATH)
        if not app_id:
            continue
        price = _dig(app, PRICE_PATH)
        rows.append(
            {
                "app_id": app_id,
                "platform": "android",
                "name": _dig(app, TITLE_PATH),
                "developer": _dig(app, DEVELOPER_PATH),
                # chart segment dims - category "all" keeps anchors poolable
                "category": "all",
                "country": country,
                "list_type": collection,
                "rank": i + 1,
                "price_usd": (price / 1_000_000) if isinstance(price, (int, float)) else None,
                "is_free": 1 if price == 0 else (0 if isinstance(price, (int, float)) else None),
                "captured_on": today,
            }
        )
    return rows
